class Solution:
    def maximumSaleItems(self, items, budget):
        n = len(items)
        factors = [it[0] for it in items]
        prices = [it[1] for it in items]
        D = [sum(1 for j in range(n) if i != j and factors[j] % factors[i] == 0) for i in range(n)]
        values = [1 + D[i] for i in range(n)]
        m = min(prices)
        best = 0
        for mask in range(1 << n):
            cost = 0
            val = 0
            for i in range(n):
                if mask & (1 << i):
                    cost += prices[i]
                    val += values[i]
            if cost <= budget:
                leftover = budget - cost
                total = val + leftover // m
                if total > best:
                    best = total
        return best

