class Solution:
    def maximumSaleItems(self, items, budget: int) -> int:
        n = len(items)
        factors = [it[0] for it in items]
        prices = [it[1] for it in items]
        D = [sum(1 for j in range(n) if i != j and factors[j] % factors[i] == 0) for i in range(n)]
        values = [1 + D[i] for i in range(n)]
        m = min(prices)
        dp = [0] * (budget + 1)
        for i in range(n):
            p = prices[i]
            v = values[i]
            if p > budget:
                continue
            for b in range(budget, p - 1, -1):
                cand = dp[b - p] + v
                if cand > dp[b]:
                    dp[b] = cand
        best = 0
        for b in range(budget + 1):
            cand = dp[b] + (budget - b) // m
            if cand > best:
                best = cand
        return best

