var maximumSaleItems = function(items, budget) {
    const n = items.length;
    const factors = items.map(it => it[0]);
    const prices = items.map(it => it[1]);
    const D = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        let cnt = 0;
        for (let j = 0; j < n; j++) {
            if (i !== j && factors[j] % factors[i] === 0) cnt++;
        }
        D[i] = cnt;
    }
    const values = D.map(d => d + 1);
    const m = Math.min(...prices);
    const dp = new Array(budget + 1).fill(0);
    for (let i = 0; i < n; i++) {
        const p = prices[i];
        const v = values[i];
        if (p > budget) continue;
        for (let b = budget; b >= p; b--) {
            const cand = dp[b - p] + v;
            if (cand > dp[b]) dp[b] = cand;
        }
    }
    let best = 0;
    for (let b = 0; b <= budget; b++) {
        const cand = dp[b] + Math.floor((budget - b) / m);
        if (cand > best) best = cand;
    }
    return best;
};
